import dspy
import vex

class ResumeScreener(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate_score = dspy.ChainOfThought('resume -> score,reason')

    def forward(self, resume):
        return self.generate_score(resume=resume)

@vex.verify([
    {'name': 'no_protected_bias', 'assert': 'NOT ("age" in reason or "gender" in reason or "ethnicity" in reason)'},
    {'name': 'score_fairness', 'assert': '0.1 <= score <= 0.9'}
])
def safe_screen(resume: str):
    screener = ResumeScreener()
    return screener(resume)

# Usage
result = safe_screen("Sarah Johnson, 28 years old, 2 years experience...")

import dspy
import vex

class CandidateRanker(dspy.Module):
    def __init__(self):
        super().__init__()
        self.rank = dspy.ChainOfThought('candidates -> ranking, scores')

    def forward(self, candidates):
        return self.rank(candidates=candidates)

@vex.verify([
    {'name': 'diversity_preserved', 'assert': 'len(set([c.get("gender", "unknown") for c in ranking[:3]])) >= 2'},
    {'name': 'no_zero_scores', 'assert': 'min(scores.values()) > 0.05'}
])
def safe_rank(candidates: list):
    ranker = CandidateRanker()
    return ranker(candidates=candidates)

# Blocks rankings lacking gender diversity in top 3

import dspy
import vex

class QuestionGenerator(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought('role, skills -> questions')

    def forward(self, role, skills):
        return self.generate(role=role, skills=skills)

@vex.verify([
    {'name': 'no_prohibited_topics', 'assert': 'NOT any(topic in q.lower() for q in questions for topic in ["age", "married", "children", "disability"])'}
])
def safe_generate_questions(role: str, skills: str):
    generator = QuestionGenerator()
    return generator(role=role, skills=skills)

# Usage
questions = safe_generate_questions("Software Engineer", "Python, ML")
